window.Assets = { "algolSystem": null, "tapes": { "casaPT.a1": "** **\n* Elliott Model 803B Simulator   *\n* Uma Casa Portuguesa            *\n* (Adapted by Luis Cunha, 2026)     *\n** **\n\n* Play \"Uma Casa Portuguesa\"\n            @entry\n            \nentry:      70  0 : 45 s2            \ns1:         70  0 : 41 play\ns2:         40 s1 : 70  0\n            \n45 s2 : 40 play\n            \nplay:       22 index / 30 tune          * Get next note duration\n            42 exit                     * Zero marks the end\n            20 temp  / 30 0             * Map duration to value\n            21 time                     \n            22 index / 30 tune          * Get next note\n         \n            20 temp  / 30 0             * Map note to frequency count\n            20 freq  : 05 six           \n            04 note0 : 20 note          * Recreate \u0027note\u0027 instruction\n      \n            44 note                     * Play the tone!\nexit:       26 index : 02 index         \n            21 index : 40 entry       \n\n* Tone generator logic\nnote0:      00  0   : 55  0\nnote:       00  0   : 55  0\n            30 freq : 34 time\n            45 note : 40 play  \n\ntime:        0                          \nfreq:        0                          \ntemp:        0                                     \nsix:         6                                         \nindex:      -1                          \n\n* Note Definitions (C Major scale + accidentals)\n* Added b2, ds3, cs4, d4 for this specific song.\n* Values are cycles (lower value = higher pitch).\n\nb2:         29                          * B2 (Si grave) ~123Hz\nc3:         27                          * C3 (Do)\nd3:         24                          * D3 (Re)\nds3:        23                          * D#3/Eb3 (Re#)\ne3:         21                          * E3 (Mi)\nf3:         20                          * F3 (Fa)\ng3:         18                          * G3 (Sol)\na3:         16                          * A3 (La)\nbb3:        15                          * Bb3 (La#)\nb3:         14                          * B3 (Si)\nc4:         13                          * C4 (Do agudo)\ncs4:        12                          * C#4 (Do# agudo)\nd4:         11                          * D4 (Re agudo - approx)\n\n* Timing definitions (approximate rhythm)\nt2:         2000                        * Crotchet/End of phrase\nt1:         1000                        * Quaver/Standard beat\n\n* Tune: Uma Casa Portuguesa\n* Format: duration, note\n\ntune:    \n            * Verso 1: Numa casa portuguesa fica bem\n            t1,c3,  t1,e3,  t1,g3,  t1,g3,  t1,g3,  t1,g3,  t1,f3,  t1,e3\n            t1,d3,  t1,b2,  t2,g3\n\n            * Verso 2: Pao e vinho sobre a mesa\n            t1,b2,  t1,d3,  t1,g3,  t1,g3,  t1,g3,  t1,g3,  t1,e3,  t2,c3\n\n            * Verso 1 Repeticao\n            t1,c3,  t1,e3,  t1,g3,  t1,g3,  t1,g3,  t1,g3,  t1,f3,  t1,e3\n            t1,d3,  t1,b2,  t2,g3\n\n            * Verso 2 Repeticao\n            t1,b2,  t1,d3,  t1,g3,  t1,g3,  t1,g3,  t1,g3,  t1,e3,  t2,c3\n\n            * Ponte: Fica bem esta franqueza\n            t1,f3,  t1,a3,  t1,c4,  t1,c4,  t1,c4,  t1,c4,  t1,bb3, t1,a3,  t1,g3,  t1,e3,  t2,c4\n            \n            * Que o povo nunca desmente\n            t1,e3,  t1,g3,  t1,c4,  t1,c4,  t1,c4,  t1,c4,  t1,a3,  t2,f3\n\n            * A alegria da pobreza...\n            t1,c3,  t1,e3,  t1,g3,  t1,g3,  t1,g3,  t1,g3,  t1,f3,  t1,e3\n            t1,d3,  t1,c3,  t1,b2,  t1,g3,  t1,g3,  t1,g3\n            t1,f3,  t1,e3,  t1,d3,  t1,c3,  t1,b2,  t1,g3,  t1,g3,  t1,g3,  t1,e3,  t2,c3\n\n            * Refrao: Quatro paredes caiadas\n            t1,c3,  t1,c3,  t1,c3,  t1,d3,  t1,d3,  t1,d3,  t2,d3\n            * Um cheirinho a alecrim\n            t1,e3,  t1,e3,  t1,e3,  t1,e3,  t1,f3,  t1,g3,  t2,f3\n            * Um cacho de uvas doiradas\n            t1,c4,  t1,a3,  t1,f3,  t1,c4,  t1,a3,  t1,f3,  t1,e3,  t2,c4\n            * Duas rosas num jardim\n            t1,e3,  t1,ds3, t1,d3,  t1,bb3, t1,cs4, t1,bb3, t2,a3\n\n            * Refrao Pt 2: Um Sao Jose de azulejos\n            t1,c3,  t1,c3,  t1,c3,  t1,d3,  t1,d3,  t1,d3,  t2,d3\n            * Mais o sol da primavera\n            t1,e3,  t1,e3,  t1,e3,  t1,e3,  t1,f3,  t1,g3,  t2,f3\n            * Uma promessa de beijos\n            t1,c4,  t1,c4,  t1,c4,  t1,c4,  t1,bb3, t1,a3,  t1,c4,  t2,bb3\n            * Dois bracos a minha espera\n            t1,bb3, t1,bb3, t1,bb3, t1,bb3, t1,bb3, t1,c4,  t1,bb3, t1,a3,  t2,c4\n\n            * Outro: E uma casa portuguesa com certeza\n            t1,f3,  t1,a3,  t1,c4,  t1,a3,  t1,d4,  t1,a3,  t1,c4,  t1,bb3, t1,g3,  t1,e3,  t2,c4\n            \n            * E, com certeza, uma casa portuguesa\n            t1,e3,  t1,g3,  t1,bb3, t1,c4,  t1,bb3, t1,d4,  t1,a3,  t1,c4\n            t1,g3,  t1,bb3, t1,e3,  t2,f3\n            \n            0\n", "music.a1": "**                              **\n* Elliott Model 803B Simulator   *\n*                                *\n* (C) Copyright Tim Baldwin 2013 *\n**                              **\n\n**\n* Play some simple music.\n*\n* This forces the console speaker to produce something that \n* approximates to a simple tune!\n**\n            @entry\n            \n* Wait for the user to change the sign bit before playing the tune\n\nentry:      70  0 : 45 s2            \ns1:         70  0 : 41 play\ns2:         40 s1 : 70  0\n            45 s2 : 40 play\n            \n* Attempt to play the tune\n\nplay:       22 index / 30 tune          * Get next note duration\n            42 exit                     * Zero marks the end\n            20 temp  / 30 0             * Map duration to value and\n            21 time                     *       store as negative\n            22 index / 30 tune          * Get next note\n            20 temp  / 30 0             * Map note to frequency count\n            20 freq  : 05 six           *       store and adjust for shift\n            04 note0 : 20 note          * Recreate \u0027note\u0027 instruction\n            44 note                     * And play the tone!\n         \nexit:       26 index : 02 index         * Get ready to play again!\n            21 index : 40 entry       \n\n* Sound something like the required note for the required duration.\n* Note that the first instruction here gets patched so the value \n* for the 55 opcode is 6 less than the note freq value - to account for\n* the time spent outside the 55 instruction.\n\nnote0:      00  0   : 55  0\nnote:       00  0   : 55  0\n            30 freq : 34 time\n            45 note : 40 play  \n\ntime:        0                          * Current note duration\nfreq:        0                          * Current note sound\n               \ntemp:        0                          * Work space               \nsix:         6                          * Adjustment factor for shifts               \nindex:      -1                          * Index into tune description\n\n* These are note definitions to produce approximate tones from the C major \n* scale (plus a B-flat).  Value is the number of 288us cycles for frequency.  \n* This is rather approximate!           * Note Freq  Cycles\n                                        * ---- ----  ------\nc3:         27                          * C3   131Hz   27\nd3:         24                          * D3   147Hz   24  \ne3:         21                          * E3   165Hz   21 \nf3:         20                          * F3   175Hz   20\ng3:         18                          * G3   196Hz   18\na3:         16                          * A3   220Hz   16\nbb3:        15                          * Bb3  233Hz   15\nb3:         14                          * B3   247Hz   14\nc4:         13                          * C4   262Hz   13\n\n* These are the timings for whole notes, half notes and quarter notes in\n* number of 288us cycles.  So 3500 is approximately 1 second.\n\nt4:         4000                        * Minim\nt2:         2000                        * Crotchet\nt15:        1500                        * Dotted quaver\nt1:         1000                        * Quaver\nt05:         500                        * Semi-quaver\n       \n* Define the tune as pairs of values: first the duration then the note\n* value.  A zero marks the end.\n\ntune:    \n            t15,c3,  t05,c3,  t2,d3,  t2,c3,  t2,f3,  t4,e3\n            t15,c3,  t05,c3,  t2,d3,  t2,c3,  t2,g3,  t4,f3\n            t15,c3,  t05,c3,  t2,c4,  t2,a3,  t2,f3,  t2,e3,  t4,d3\n            t15,bb3, t05,bb3, t2,a3,  t2,f3,  t2,g3,  t4,f3              \n            0 \n", "hello.algol": "HELLO\u0027\nBEGIN\n    COMMENT SIMPLE HELLO WORLD PROGRAM\u0027\n    PRINT PUNCH(3), #HELLO WORLD#L??\u0027\nEND\u0027\n", "hello1.a1": "**                              **\n* Elliott Model 803B Simulator   *\n*                                *\n* (C) Copyright Tim Baldwin 2009 *\n**                              **\n\n**\n* Simple Hello World Example\n*\n* Prints \"HELLO WORLD?\" to the teletype.\n*\n* This program will be loaded into the high-end of store and after loading\n* will automatically jump to the entry point address to run the code.\n**\n        @entry                  * Entry point\n\nentry:\nloop:   22 index / 30 hello     * Get next character\n        42 end   : 20 char      * Check for zero at end of text, otherwise save character\n        00 char  / 74 4096      * Write character to teletype\n        40 loop                 * Loop\nend:    74 4125  : 74 4126      * Write [CR][LF] to terminate line\n        72 8191                 * Exit\n\nchar:   0                       * Character workspace\nindex: -1                       * Index into text\nhello: \u0027Hello World!\u0027           * Text: will be telecode [LS]HELLO WORLD[FS]?\n        0                       * Zero marks end of text\n", "pi4.algol": "PI4\u0027\nBEGIN\n\nComment ****************************************************************\n        ***                                                          ***\n        *** This calculation of PI uses the Bailey-Borwein-Plouffe   ***\n        *** algorithm, whereby PI = Sum [K=0 to Inf] (1/16)**K       ***\n        ***         *( 4/(8*K+1) -2/(8*K+4) -1/(8K+5) -1/(8*K+6) ).  ***\n        *** At each iteration, the four arrays BFrac1 to BFrac4 are  ***\n        *** populated with the binary expansions of the fractional   ***\n        *** terms, then these are combined, and finally shifted by an***\n        *** amount corresponding to the factor (1/16)**K, upon which ***\n        *** this is added to the accumulating total.  Hence we get   ***\n        *** an answer of gradually increasing precision, viewable    ***\n        *** by setting bit 2 of the console word generator.          ***\n        ***                                                          ***\n        *** Each iteration increases the precision by slightly       ***\n        *** better than 4 binary bits, so we can estimate the decimal***\n        *** precision correspondingly at each iteration, or otherwise***\n        *** by simply comparing results of consecutive iterations.   ***\n        ***                                                          ***\n        *** Diagnostics  Setting BLine causes binary dump of some    ***\n        *** ===========      arrays - to see all remove the Comments ***\n        ***              Setting One on the word generator causes a  ***\n        ***                  trace of significant operations         ***\n        ***              Setting Two on the word generator shows the ***\n        ***                  decimal accumulation at EVERY iteration ***\n        ***                                                          ***\n        *** Author:  Bob Firth                                       ***\n        *** Written: June,July 2010                                  ***\n        *** Contact: General_Factotum@hotmail.co.uk                  ***\n        ***                                                          ***\n        *** Comment: The machine code of the 803/503 is not          ***\n        ***          particularly suited to multi-word precision     ***\n        ***          arithmetic, mainly because of the absence of    ***\n        ***          double-length add and subtract.  Nevertheless   ***\n        ***          it is possible to program around this by        ***\n        ***          detecting and handling overflow while processing***\n        ***          the lower order word.                           ***\n        ***                                                          ***\n        ****************************************************************\u0027\n\n\nPROCEDURE PWRDS(Ident,AStart,ASize)\u0027\n        VALUE   AStart,ASize\u0027\n        INTEGER AStart,ASize\u0027\n        STRING  Ident\u0027\n\nComment *** Dumps binary representation of elements of array         ***\n        *** starting at AStart, length 1+ASize                       ***\n        ****************************************************************\u0027\n\nBEGIN   INTEGER BLine,NoBits,NoCHs,Count,Word\u0027\n        SWITCH S:=SPACE,LOOP,NEXT,EXIT,GETOUT\u0027\n        BLine   :=524288\u0027\n\n        Elliott(7,0,0     ,0,0,3,BLine )\u0027\n        Elliott(4,2,GETOUT,0,0,0,0     )\u0027\n\n        FOR Count:=0 STEP 1 UNTIL ASize DO BEGIN\n                Elliott(7,0,0     ,0,0,3,BLine )\u0027\n                Elliott(4,2,EXIT  ,0,0,0,0     )\u0027\n                PRINT L1??,Ident,sameline,digits(3),Count,) ?\u0027\n                NOBITS  :=-39\u0027\n                Elliott(3,0,AStart,0,0,4,Count)\u0027\n                Elliott(2,0,4     ,1,3,0,0     )\u0027\n                Elliott(2,0,Word  ,0,0,0,0     )\u0027\n        SPACE:  PRINT  ?\u0027\n                NOCHS   :=-2\u0027\n        LOOP:   ELLIOTT(3,2,NoBits,0,4,2,EXIT  )\u0027\n                IF WORD LESS 0 THEN PRINT 1?\u0027\n                IF WORD GREQ 0 THEN PRINT 0?\u0027\n                ELLIOTT(3,0,Word  ,0,5,5,1     )\u0027\n                ELLIOTT(2,0,Word  ,0,4,3,NEXT  )\u0027\n        NEXT:   ELLIOTT(3,2,NoCHs ,0,4,2,SPACE )\u0027\n                ELLIOTT(4,0,LOOP  ,0,0,0,0     )\u0027\n        EXIT:                              END\u0027\nGETOUT:\nEND PWRDS\u0027\nComment ================================================================\u0027\n\n\nPROCEDURE INTDV(DVDend,DIVsor,AStart,ASize)\u0027\n        VALUE   DVDend,DIVsor,AStart,ASize\u0027\n        INTEGER DVDend,DIVsor,AStart,ASize\u0027\n\nComment *** Divides integer word DVDend by integer word DIVsor,      ***\n        *** result is stored in array ARRAY[0:ASize]                 ***\n        *** where whole part of quotient goes to ARRAY[0]            ***\n        *** and fractional part populates rest of array.             ***\n        *** Array position and length given by AStart and ASize+1    ***\n        ****************************************************************\u0027\n\nBEGIN   INTEGER Maxpos,One,Remain,Count,Point\u0027\n        SWITCH S:=NOTRAC,LOOP\u0027\n        Maxpos  :=274877906943\u0027\n        One     :=1\u0027\n\n        Elliott(7,0,0     ,0,0,3,One   )\u0027\n        Elliott(4,2,NOTRAC,0,0,0,0     )\u0027\n        PRINT ##L1?Dividing ?,SAMELINE,DIGITS(1),DVDend,# by ?,DIGITS(5),DIVsor\u0027\nNOTRAC: Elliott(2,6,Remain,0,2,6,Count )\u0027\n        Elliott(3,0,AStart,0,2,0,Point )\u0027\n        Elliott(3,0,DVDend,0,2,0,4     )\u0027\n        Elliott(5,0,38    ,0,0,0,0     )\u0027\nLOOP:   Elliott(3,0,Remain,0,5,6,DIVsor)\u0027\n        Elliott(0,0,Point ,1,2,0,0     )\u0027\n        Elliott(5,2,DIVsor,0,5,7,0     )\u0027\n        Elliott(0,7,4     ,0,0,3,Maxpos)\u0027\n        Elliott(2,0,Remain,0,2,6,4     )\u0027\n        Elliott(2,2,Point ,0,0,0,0     )\u0027\n        Elliott(3,2,Count ,0,0,5,ASize )\u0027\n        Elliott(5,1,0     ,0,4,1,LOOP  )\u0027\nEND INTDV\u0027\nComment ================================================================\u0027\n\n\nPROCEDURE COMBI(T1Strt,T2Strt,T3Strt,T4Strt,TTStrt,Max)\u0027\n        VALUE   T1Strt,T2Strt,T3Strt,T4Strt,TTStrt,Max\u0027\n        INTEGER T1Strt,T2Strt,T3Strt,T4Strt,TTStrt,Max\u0027\n\nComment *** Take (binary fraction at) T1Strt, subtract that at T2Strt***\n        *** and at T3Strt and at T4Strt, and put result at TTStrt    ***\n        ****************************************************************\u0027\n\nBEGIN   INTEGER Maxpos,One,Count,Carry\u0027\n        Switch  S:=LOOP,UFLO1,SKIP1,UFLO2,SKIP2,UFLO3,SKIP3,UFLO4,SKIP4\u0027\n        Maxpos  :=274877906943\u0027\n        One     :=1\u0027\n\n        T1Strt  :=T1Strt+Max\u0027\n        T2Strt  :=T2Strt+Max\u0027\n        T3Strt  :=T3Strt+Max\u0027\n        T4Strt  :=T4Strt+Max\u0027\n        TTStrt  :=TTStrt+Max\u0027\n        Elliott(3,0,Max   ,0,2,0,Count )\u0027\n        Elliott(2,6,Carry ,0,2,6,4     )\u0027\nLOOP:   Elliott(0,0,T1Strt,1,3,0,0     )\u0027\n        Elliott(0,0,T2Strt,1,0,5,0     )\u0027\n        Elliott(4,1,UFLO1 ,0,4,0,SKIP1 )\u0027\nUFLO1:  Elliott(0,3,MaxPos,0,2,2,4     )\u0027\nSKIP1:  Elliott(0,0,T3Strt,1,0,5,0     )\u0027\n        Elliott(4,1,UFLO2 ,0,4,0,SKIP2 )\u0027\nUFLO2:  Elliott(0,3,MaxPos,0,2,2,4     )\u0027\nSKIP2:  Elliott(0,0,T4Strt,1,0,5,0     )\u0027\n        Elliott(4,1,UFLO3 ,0,4,0,SKIP3 )\u0027\nUFLO3:  Elliott(0,3,MaxPos,0,2,2,4     )\u0027\nSKIP3:  Elliott(0,0,0     ,0,0,5,Carry )\u0027\n        Elliott(4,1,UFLO4 ,0,4,0,SKIP4 )\u0027\nUFLO4:  Elliott(0,3,MaxPos,0,2,2,4     )\u0027\nSKIP4:  Elliott(0,0,TTStrt,1,2,0,0     )\u0027\n        Elliott(3,6,4     ,0,2,0,Carry )\u0027\n        Elliott(3,0,One   ,0,2,7,T1Strt)\u0027\n        Elliott(2,7,T2Strt,0,2,7,T3Strt)\u0027\n        Elliott(2,7,T4Strt,0,2,7,TTStrt)\u0027\n        Elliott(0,0,0     ,0,3,7,Count )\u0027\n        Elliott(0,1,0     ,0,4,1,LOOP  )\u0027\nEND COMBI\u0027\nComment ================================================================\u0027\n\n\nPROCEDURE SHIFT(Expone,TTStrt,SHStrt,Max)\u0027\n        VALUE   Expone,TTStrt,SHStrt,Max\u0027\n        INTEGER Expone,TTStrt,SHStrt,Max\u0027\n\nComment *** Shift contents of array at TTStrt down by Expone*4 bits  ***\n        *** and place result at array SHStrt, both length Max        ***\n        ****************************************************************\u0027\n\nBEGIN   INTEGER Maxpos,One,Count,ShiftB,ShiftL,ShiftR,ShiftW,Source\u0027\n        Switch  S:=DONE,NOTRAC,MORE,SHIF1,NONE1,NEXT1,SHIF2,NONE2,NEXT2,NOSHIF,EXIT\u0027\n        Maxpos  :=274877906943\u0027\n        One     :=1\u0027\n\n        Count   :=Expone DIV 19\u0027\n        ShiftB  :=( Expone - Count*19 )*4\u0027\n        ShiftW  :=Count *2\u0027\n        ShiftL  :=ShiftR  :=Source  :=0\u0027\n\n        If ShiftB GREQ 60 then BEGIN\n                ShiftW  :=ShiftW +1\u0027\n                ShiftL  :=76 - ShiftB\u0027\n                Goto DONE\u0027\n                               END\u0027\n        If ShiftB GREQ 40 then BEGIN\n                ShiftW  :=ShiftW +1\u0027\n                ShiftR  :=ShiftB - 38\u0027\n                Source  :=1\u0027\n                Goto DONE\u0027\n                               END\u0027\n        If ShiftB GREQ 20 then BEGIN\n                ShiftL  :=38 - ShiftB\u0027\n                Goto DONE\u0027\n                               END\u0027\n        If ShiftB GREQ  0 then BEGIN\n                ShiftR  :=ShiftB\u0027\n                Source  :=1\u0027\n                               END\u0027\n\nDONE:   Elliott(7,0,0     ,0,0,3,One   )\u0027\n        Elliott(4,2,NOTRAC,0,0,0,0     )\u0027\n        Print l1?Shift Parameters?,SAMELINE,DIGITS(3),Count,ShiftB,ShiftL,ShiftR,ShiftW,Source\u0027\n\nNOTRAC: Elliott(0,0,0     ,0,2,6,Count )\u0027\nMORE:   Elliott(3,0,Count ,0,0,5,ShiftW)\u0027\n        Elliott(4,1,NONE1 ,0,0,4,TTStrt)\u0027\n        Elliott(2,0,4     ,1,3,0,0     )\u0027\nSHIF1:  Elliott(5,0,38    ,0,4,0,NEXT1 )\u0027\nNONE1:  Elliott(0,6,0     ,0,4,0,SHIF1 )\u0027\nNEXT1:  Elliott(3,0,Count ,0,0,5,ShiftW)\u0027\n        Elliott(0,5,One   ,0,4,1,NONE2 )\u0027\n        Elliott(0,4,TTStrt,0,0,0,0     )\u0027\n        Elliott(2,0,4     ,1,3,0,0     )\u0027\nSHIF2:  Elliott(4,0,NEXT2 ,0,0,0,0     )\u0027\nNONE2:  Elliott(0,6,0     ,0,0,0,0     )\u0027\nNEXT2:  Elliott(0,0,ShiftL,1,5,4,0     )\u0027\n        Elliott(0,0,ShiftR,1,5,0,0     )\u0027\n        Elliott(0,3,Maxpos,0,2,0,4     )\u0027\n        Elliott(3,0,Source,0,4,2,NOSHIF)\u0027\n        Elliott(5,7,0     ,0,2,0,4     )\u0027\nNOSHIF: Elliott(3,0,4     ,0,0,0,0     )\u0027\n        Elliott(0,0,SHStrt,1,2,0,0     )\u0027\n        Elliott(2,2,SHStrt,0,3,0,Count )\u0027\n        Elliott(0,4,One   ,0,2,0,Count )\u0027\n        Elliott(0,5,Max   ,0,0,5,One   )\u0027\n        Elliott(4,1,MORE  ,0,4,3,EXIT  )\u0027\nEXIT:\nEND SHIFT\u0027\nComment ================================================================\u0027\n\n\nPROCEDURE ACCUM(BStart,BSize,TStart,TSize)\u0027\n        VALUE   BStart,BSize,TStart,TSize\u0027\n        INTEGER BStart,BSize,TStart,TSize\u0027\n\nComment *** Add contents of extended integer at BStart size BSize    ***\n        *** into extended integer at TStart, size TSize.             ***\n        ****************************************************************\u0027\n\nBEGIN   INTEGER Maxpos,One,Count,Carry\u0027\n        SWITCH S:=LOOP,OFLO,SKIP,EXIT\u0027\n        Maxpos  :=274877906943\u0027\n        One     :=1\u0027\n\n        IF BSize NOTEQ TSize THEN BEGIN\n                PRINT l1?Illegal parameters to procedure ACCUM?\u0027\n                GOTO EXIT\u0027\n                                  END\u0027\n        TStart  :=TStart+BSize\u0027\n        BStart  :=BStart+BSize\u0027\n        Elliott(3,0,BSize ,0,2,0,Count )\u0027\n        Elliott(2,6,Carry ,0,2,6,4     )\u0027\nLOOP:   Elliott(0,0,TStart,1,3,0,0     )\u0027\n        Elliott(0,0,BStart,1,0,4,0     )\u0027\n        Elliott(4,3,OFLO  ,0,4,0,SKIP  )\u0027\nOFLO:   Elliott(0,3,MaxPos,0,2,2,4     )\u0027\nSKIP:   Elliott(0,4,Carry ,0,0,0,0     )\u0027\n        Elliott(0,0,TStart,1,2,0,0     )\u0027\n        Elliott(3,6,4     ,0,2,0,Carry )\u0027\n        Elliott(3,0,One   ,0,2,7,BStart)\u0027\n        Elliott(0,0,0     ,0,2,7,TStart)\u0027\n        Elliott(3,7,Count ,0,0,1,0     )\u0027\n        Elliott(4,1,LOOP  ,0,0,0,0     )\u0027\nEXIT:\nEND CBTOD\u0027\nComment ================================================================\u0027\n\n\nPROCEDURE CBTOD(BStart,BSize,DStart,DSize)\u0027\n        VALUE   BStart,BSize,DStart,DSize\u0027\n        INTEGER BStart,BSize,DStart,DSize\u0027\n\nComment *** Converts binary fraction in array at BStart length       ***\n        *** 1+BSize to Decimal fraction at DStart length 1+DSize     ***\n        ****************************************************************\u0027\n\nBEGIN   INTEGER Maxpos,Power,One,BCount,DCount,Carry,Item,Point\u0027\n        SWITCH S:=START,LOOP,OFLO,SKIP,EXIT\u0027\n        Maxpos  :=274877906943\u0027\n        Power   :=10000000000\u0027\n        One     :=1\u0027\n\n        Elliott(3,0,DSize ,0,2,1,DCount)\u0027\nSTART:  Elliott(0,6,BStart,1,1,0,0     )\u0027\n        Elliott(0,0,DStart,1,2,0,0     )\u0027\n        Elliott(3,0,DCount,0,4,2,EXIT  )\u0027\n        Elliott(2,2,DCount,0,2,6,Carry )\u0027\n        Elliott(3,0,BSize ,0,2,1,BCount)\u0027\n        Elliott(3,0,BStart,0,0,4,BSize )\u0027\n        Elliott(2,0,Point ,0,0,0,0     )\u0027\n\nLOOP:   Elliott(0,0,Point ,1,3,0,0     )\u0027\n        Elliott(5,2,Power ,0,2,0,4     )\u0027\n        Elliott(5,7,0     ,0,0,4,Carry )\u0027\n        Elliott(4,3,OFLO  ,0,4,0,SKIP  )\u0027\nOFLO:   Elliott(0,3,Maxpos,0,2,2,4     )\u0027\nSKIP:   Elliott(0,0,Point ,1,2,0,0     )\u0027\n        Elliott(3,0,4     ,0,2,0,Carry )\u0027\n        Elliott(3,0,One   ,0,2,7,Point )\u0027\n        Elliott(3,2,BCOUNT,0,4,1,LOOP  )\u0027\n        Elliott(2,2,DStart,0,4,0,START )\u0027\nEXIT:\nEND CBTOD\u0027\nComment ================================================================\u0027\n\n\nPROCEDURE PDARY(DStart,DSize)\u0027\n        VALUE   DStart,DSize\u0027\n        INTEGER DStart,DSize\u0027\n\nComment *** Print decimal number at DStart, and fractional component ***\n        *** at DStart+1, length DSize                                ***\n        ****************************************************************\u0027\n\nBEGIN   INTEGER Cols,Count,Word\u0027\n        Cols    :=6\u0027\n        Elliott(0,0,Dstart,1,3,0,0     )\u0027\n        Elliott(2,0,Word  ,0,0,0,0     )\u0027\n        PRINT l1??,sameline,Digits(1),Word,.?\u0027\n        For Count:=1 step 1 until DSize DO BEGIN\n                Elliott(2,2,Dstart,1,3,0,0     )\u0027\n                Elliott(2,0,Word  ,0,0,0,0     )\u0027\n                IF ( Count-1 ) = ( ( Count-1 ) DIV Cols )*Cols THEN BEGIN\n                        IF ( Count-1 ) GREQ 1 THEN PRINT l1?   ?\u0027 END\u0027\n                PRINT sameline,leadzero(0?),Digits(10),Word\u0027\n                                           END\u0027\nEND PDARY\u0027\nComment ================================================================\u0027\n\n\nINTEGER PROCEDURE ESTIM(Expone)\u0027\n                VALUE   Expone\u0027\n                INTEGER Expone\u0027\n\nComment *** Estimate number of decimal places precision available    ***\n        *** after term Expone contributed.                           ***\n        ****************************************************************\u0027\n\nBEGIN   REAL    Temp\u0027\n        Temp    :=4/(8*Expone+1)-2/(8*Expone+4)-1/(8*Expone+5)-1/(8*Expone+6)\u0027\n        ESTIM   :=entier((Expone*LN(16)-LN(Temp))/LN(10)+0.5)\u0027\nEND ESTIM\u0027\nComment ================================================================\u0027\n\n\nPROCEDURE TRACE(TEXT)\u0027\n        STRING  TEXT\u0027\n\nComment *** Trace program flow if bit 1 set                          ***\n        ****************************************************************\u0027\n\nBEGIN   INTEGER One\u0027\n        SWITCH S:=NOTRAC\u0027\n        One     :=1\u0027\n\n        Elliott(7,0,0     ,0,0,3,One   )\u0027\n        Elliott(4,2,NOTRAC,0,0,0,0     )\u0027\n        PRINT TEXT\u0027\nNOTRAC:\nEND TRACE\u0027\nComment ================================================================\u0027\n\n\nPROCEDURE CALPI(MaxTrm,BMax,DMax)\u0027\n        VALUE   MaxTrm,BMax,DMax\u0027\n        INTEGER MaxTrm,BMax,DMax\u0027\n\nComment *** Perform calculation of PI using algorithm described above***\n        *** MaxTrm is the number of terms to be calculated           ***\n        ***   BMax is words allocated to fractional part of result   ***\n        ***   DMax is words allocated (10 digits/word) to decimal    ***\n        ***                                         part of result   ***\n        ****************************************************************\u0027\n\nBEGIN   INTEGER Array BFrac1[0:BMax],BFrac2[0:BMax],BFrac3[0:BMax],BFrac4[0:BMax]\u0027\n        INTEGER Array BFracT[0:BMax],BShift[0:BMax],BReslt[0:BMax],BOutpt[0:BMax]\u0027\n        INTEGER Array DOutpt[0:DMax]\u0027\n        INTEGER Two,Count,Term,Expone,EPlace,DWords\u0027\n        SWITCH S:=SHOW,NOSHOW\u0027\n        Two     :=2\u0027\n\n        FOR Count:=0 STEP 1 UNTIL BMax DO\n                BReslt[Count]:=0\u0027\n\n        FOR Term:=1 STEP 1 UNTIL MaxTrm DO BEGIN\n        Expone  :=Term-1\u0027\n        PRINT l1?Adding term ?,sameline,digits(4),Term\u0027\n\n        INTDV(4,8*Expone+1,ADDRESS(BFrac1),BMax)\u0027\nComment PWRDS(BFrac1?,ADDRESS(BFrac1),BMax)\u0027\n\n        INTDV(2,8*Expone+4,ADDRESS(BFrac2),BMax)\u0027\nComment PWRDS(BFrac2?,ADDRESS(BFrac2),BMax)\u0027\n\n        INTDV(1,8*Expone+5,ADDRESS(BFrac3),BMax)\u0027\nComment PWRDS(BFrac3?,ADDRESS(BFrac3),BMax)\u0027\n\n        INTDV(1,8*Expone+6,ADDRESS(BFrac4),BMax)\u0027\nComment PWRDS(BFrac4?,ADDRESS(BFrac4),BMax)\u0027\n\n        TRACE(l1?Combine fractions...?)\u0027\n        COMBI(ADDRESS(BFrac1),ADDRESS(BFrac2),ADDRESS(BFrac3),ADDRESS(BFrac4),ADDRESS(BFracT),BMax)\u0027\nComment PWRDS(BFracT?,ADDRESS(BFracT),BMax)\u0027\n\nComment TRACE(l1?Shift down...?)\u0027\n        SHIFT(Expone,ADDRESS(BFracT),ADDRESS(BShift),BMax)\u0027\n        PWRDS(BShift?,ADDRESS(BShift),BMax)\u0027\n\n        TRACE(l1?Accumulate...?)\u0027\n        ACCUM(ADDRESS(BShift),BMax,ADDRESS(BReslt),BMax)\u0027\nComment PWRDS(BReslt?,ADDRESS(BReslt),BMax)\u0027\n\n        IF Term GREQ MaxTrm-2 THEN GOTO SHOW\u0027\n        Elliott(7,0,0     ,0,0,3,Two   )\u0027\n        Elliott(4,2,NOSHOW,0,0,0,0     )\u0027\nSHOW:   TRACE(l1?Convert to Decimal...?)\u0027\n        FOR Count:=0 STEP 1 UNTIL BMax DO BOutpt(Count):=BReslt(Count)\u0027\n        CBTOD(ADDRESS(BOutpt),BMax,ADDRESS(DOutpt),DMax)\u0027\n        EPlace  :=ESTIM(Expone)\u0027\n        DWords  :=(EPlace+15) DIV 10\u0027\n        IF DWords GR DMax THEN DWords :=DMax\u0027\n        PRINT SAMELINE, yields value for PI:-?\u0027\n        PDARY(ADDRESS(DOutpt),DWords)\u0027\n        PRINT l1?Estimated accurate to?,sameline,digits(4),EPlace,  digitsl1??\u0027\nNOSHOW:                                    END\u0027\n\nEND CALPI\u0027\nComment ================================================================\n        ================================================================\n        ================================================================\u0027\n\n\nBEGIN   INTEGER N,BMax,DMax,Expone,MaxTrm\u0027\n        REAL    DTB\u0027\n        SWITCH S:=LOOP1,LOOP2,ONYERBIKE\u0027\n        Reader(2)\u0027\n         Punch(3)\u0027\n        Digits(4)\u0027\n\nComment The most efficient use of array space is when both Binary and Decimal arrays\n        hold the same precision, which occurs when DMax = BMax * ( LN(2**39)/LN(10**10))\n                                                        = BMax * 1.17402\n\n        To achieve an accuracy of D decimal digits, this is guaranteed by\n        using number of iterations given by:     Maxtrm = D * ( LN(10)/LN(16) )\n                                                        = D * 0.830482\n        where DMax decimal array entries hold 10*DMax digits\n\n        For a more accurate estimate, keep increasing Expone until\n        ( Expone*LN(16)-LN(4/(8*Expone+1)-2/(8*Expone+4)-1/(8*Expone+5)-1/(8*Expone+6)) )/LN(10) \u003eD\n             and then set MaxTrm :=Expone+1\u0027\n\n        Read N\u0027\n        IF N LESSEQ 0 THEN BEGIN\n                PRINT Invalid number?\u0027\n                GOTO ONYERBIKE\u0027\n                           END\u0027\n\n        DMax    :=( N+9 ) DIV 10\u0027\n        BMax    :=entier( DMax*(10*LN(10))/(39*LN(2)) )+2\u0027\n\n        PRINT l1?Required decimal places    ?,sameline,N\u0027\n        PRINT l1?Array size, Decimal storage?,sameline,DMax\u0027\n        PRINT l1?Array size, Binary storage ?,sameline,BMax\u0027\n        PRINT l1?Overall array space reqd.  ?,sameline,DMax+8*BMax\u0027\n\n        Expone  :=0\u0027\nLOOP1:  Expone  :=Expone+10\u0027\n        IF ESTIM(Expone) LESSEQ (N-1) THEN GOTO LOOP1\u0027\n\nLOOP2:  Expone  :=Expone-1\u0027\n        IF ESTIM(Expone) GREQ   (N+1) THEN GOTO LOOP2\u0027\n        Expone  :=Expone+1\u0027\n        Maxtrm  :=Expone+1\u0027\n        PRINT l1?Required number iterations ?,sameline,Maxtrm\u0027\n\n        PRINT l2?Calculation of PI using?,sameline,MaxTrm, iterations?\u0027\n        PRINT l1?=======================================?,l1??\u0027\n\n        CALPI(MaxTrm,BMax,DMax)\u0027\nONYERBIKE:\nEND\u0027\nComment ================================================================\u0027\nEND\u0027\n\n", "sortacm.algol": "QUICKSORT FROM CACM, JULY 1961\u0027\n\nBEGIN\n    COMMENT **                      **\u0027\n    COMMENT * ELLIOTT 803B SIMULATOR *\u0027\n    COMMENT *                        *\u0027\n    COMMENT * (C) TIM BALDWIN 2013   *\u0027\n    COMMENT **                      **\u0027\n\n    COMMENT **                                                             **\u0027\n    COMMENT * AN IMPLEMENTATION OF THE QUICKSORT ALGORITHM.                 *\u0027\n    COMMENT *                                                               *\u0027\n    COMMENT * THE IMPLEMENTATION OF THE PROCEDURES QUICKSORT AND PARTITION  *\u0027\n    COMMENT * ARE EXACTLY AS PRESENTED IN THE ORIGINAL JULY 1961 EDITION OF *\u0027\n    COMMENT * THE COMMUNICATIONS OF THE ACM, VOLUME 4, ISSUE 7.             *\u0027\n    COMMENT **                                                             **\u0027\n\n    INTEGER SEED, SIZE, REPEAT\u0027\n\n\n    INTEGER PROCEDURE RANDOM(M,N)\u0027  VALUE M,N\u0027  INTEGER M,N\u0027\n        COMMENT RETURNS A PSUEDO-RANDOM INTEGER BETWEEN M AND N.\u0027\n    BEGIN\n        INTEGER PROCEDURE MOD(P,Q)\u0027  VALUE P,Q\u0027  INTEGER P,Q\u0027\n            MOD := P - (P DIV Q * Q)\u0027\n        SEED := MOD(SEED*4099, 8388608)\u0027\n        RANDOM := MOD(SEED, (N-M)+1) + M\u0027\n    END RANDOM\u0027\n\n\n    PROCEDURE EXCHANGE(X,Y)\u0027  INTEGER X,Y\u0027\n        COMMENT EXCHANGE THE TWO VALUES X AND Y\u0027\n    BEGIN\n        INTEGER Z\u0027\n        Z := X\u0027  X := Y\u0027  Y := Z\u0027\n    END EXCHANGE\u0027\n\n\n    PROCEDURE PARTITION(A,M,N,I,J)\u0027  VALUE M,N\u0027\n            INTEGER ARRAY A\u0027  INTEGER M,N,I,J\u0027\n        COMMENT I AND J ARE OUTPUT VARIABLES, AND A IS THE ARRAY (WITH\n                SUBSCRIPT BOUNDS M:N) WHICH IS OPERATED UPON BY THIS\n                PROCEDURE. PARTITION TAKES THE VALUE X OF A RANDOM ELEMENT\n                OF THE ARRAY A, AND REARRANGES THE VALUES OF THE ELEMENTS\n                OF THE ARRAY IN SUCH A WAY THAT THERE EXIST INTEGERS I AND J\n                WITH THE FOLLOWING PROPERTIES:\n                  M LESSEQ J LESS I LESSEQ N PROVIDED M LESS N\n                  A(R) LESSEQ X FOR M LESSEQ R LESSEQ J\n                  A(R) = X FOR J LESS R LESS I\n                  A(R) GREQ X FOR I LESSEQ R LESSEQ N\n                THE PROCEDURE USES AN INTEGER PROCEDURE RANDOM(M,N) WHICH\n                CHOOSES EQUIPROBABLY A RANDOM INTEGER F BETWEEN M AND N, AND\n                ALSO A PROCEDURE EXCHANGE, WHICH EXCHANGES THE VALUES OF ITS\n                TWO PARAMETERS\u0027\n    BEGIN\n        INTEGER X\u0027  INTEGER F\u0027\n        SWITCH SS := UP,DOWN,CHANGE\u0027\n\n        F := RANDOM(M,N)\u0027  X := A(F)\u0027\n        I := M\u0027  J := N\u0027\n     UP:\n        FOR I := I STEP 1 UNTIL N DO\n            IF X LESS A(I) THEN GOTO DOWN\u0027\n        I := N\u0027\n     DOWN:\n        FOR J := J STEP -1 UNTIL M DO\n            IF A(J) LESS X THEN GOTO CHANGE\u0027\n        J := M\u0027\n     CHANGE:\n        IF I LESS J THEN BEGIN\n             EXCHANGE(A(I),A(J))\u0027\n             I := I + 1\u0027  J := J - 1\u0027\n             GOTO UP\u0027\n        END\n        ELSE IF I LESS F THEN BEGIN\n             EXCHANGE(A(I),A(F))\u0027\n             I := I + 1\u0027\n        END\n        ELSE IF F LESS J THEN BEGIN\n             EXCHANGE(A(F),A(J))\u0027\n             J := J - 1\u0027\n        END\n    END PARTITION\u0027\n\n\n    PROCEDURE QUICKSORT(A,M,N)\u0027  VALUE M,N\u0027\n            INTEGER ARRAY A\u0027  INTEGER M,N\u0027\n        COMMENT QUICKSORT IS A VERY FAST AND CONVENIENT METHOD OF\n                SORTING AN ARRAY IN THE RANDOM-ACCESS STORE OF A COMPUTER.\n                THE ENTIRE CONTENTS OF THE STORE MAY BE SORTED, SINCE NO\n                EXTRA SPACE IS REQUIRED. THE AVERAGE NUMBER OF COMPARISONS\n                MADE IS 2(M-N)LN(N-M), AND THE AVERAGE NUMBER OF EXCHANGES\n                IS ONE SIXTH THIS AMOUNT. SUITABLE REFINEMENTS OF THIS\n                METHOD WILL BE DESIRABLE FOR ITS IMPLEMENTATION ON ANY\n                ACTUAL COMPUTER\u0027\n    BEGIN\n        INTEGER I, J\u0027\n        IF M LESS N THEN BEGIN\n            PARTITION(A,M,N,I,J)\u0027\n            QUICKSORT(A,M,J)\u0027\n            QUICKSORT(A,I,N)\u0027\n        END\n    END QUICKSORT\u0027\n\n\n    PROCEDURE PRINTDATA(S,DATA,SIZE)\u0027  VALUE SIZE\u0027\n            STRING S\u0027  INTEGER SIZE\u0027  INTEGER ARRAY DATA\u0027\n        COMMENT PRINT DATA VALUES\u0027\n    BEGIN\n        INTEGER I\u0027\n        PRINT S\u0027\n        FOR I := 1 STEP 1 UNTIL SIZE DO\n            PRINT PREFIX(# ?), DIGITS(3), DATA(I)\u0027\n    END PRINTDATA\u0027\n\n\n    READ SEED, REPEAT, SIZE\u0027\n\n    BEGIN\n        INTEGER I\u0027  INTEGER ARRAY DATA(1:SIZE)\u0027\n\n        PUNCH(3)\u0027\n\n        FOR REPEAT := REPEAT STEP -1 UNTIL 1 DO BEGIN\n\n            COMMENT GENERATE SOME RANDOM NUMBERS FROM 1 TO 999, PRINT IN THE\n                    ORIGINAL ORDER, SORT AND PRINT AGAIN IN SORTED ORDER\u0027\n\n            FOR I := 1 STEP 1 UNTIL SIZE DO\n                DATA(I) := RANDOM(1,999)\u0027\n            PRINTDATA(##L?ORIGINAL DATA:?,DATA,SIZE)\u0027\n\n            QUICKSORT(DATA,1,SIZE)\u0027\n            PRINTDATA(##L?SORTED DATA:  ?,DATA,SIZE)\u0027\n\n            PRINT ##L2??\u0027\n        END\u0027\n    END\u0027\nEND\u0027\n\nSEED 123\nREPEAT 3 TIMES WITH 12 VALUES\nSEED 654\nREPEAT 4 TIMES WITH 10 VALUES\n\n", "trig.algol": "Trigonometric Table;\n\nBEGIN\n COMMENT **                      **;\n COMMENT * Elliott 803B simulator *;\n COMMENT *                        *;\n COMMENT * (C) Tim Baldwin 2009   *;\n COMMENT **                      **;\n\n COMMENT **                                                        **;\n COMMENT * Print out a table of some x and sin(x) and cos(x) values *;\n COMMENT **                                                        **;\n\n    COMMENT Program constants;\n    INTEGER size;  REAL pi;\n\n    COMMENT Create tables of angles in degrees and radians;\n    PROCEDURE createAngles(s, d, r);\n    VALUE s; INTEGER s; INTEGER ARRAY d; REAL ARRAY r;\n    BEGIN\n        INTEGER i, a;\n        a := 360/(s-1);\n\n        FOR i := 1 STEP 1 UNTIL s DO BEGIN\n            d[i] := (i-1) * a;\n            r[i] := (d[i]/180) * pi;\n        END loop;\n    END createAngles;\n\n    size := 25;\n    pi := 3.141592;\n\n    COMMENT Print sine and cosine tables;\n    BEGIN\n        INTEGER i;\n        INTEGER ARRAY deg[1:size];\n        REAL ARRAY rad[1:size];\n        REAL sv, cv;\n\n        createAngles(size, deg, rad);\n\n        punch(3);    COMMENT Send all output to the teletype;\n        PRINT #      x deg?,#       x rad?,#      sin(x)?,#      cos(x)#L??;\n        PRINT #    -------?,#    --------?,#   ---------?,#   ---------#L??;\n\n        FOR i := 1 STEP 1 UNTIL size DO BEGIN\n            sv := sin(rad[i]);  cv := cos(rad[i]);\n            PRINT prefix(#  ?), deg[i], aligned(2,6), rad[i];\n            PRINT prefix(#  ?), aligned(2,6), sv, cv, ##L??;\n        END print loop;\n    END;\nEND program;\n", "sort.algol": "QuickSort;\n\nBEGIN\n    COMMENT **                      **;\n    COMMENT * Elliott 803B simulator *;\n    COMMENT *                        *;\n    COMMENT * (C) Tim Baldwin 2009   *;\n    COMMENT **                      **;\n\n    COMMENT **                                             **; \n    COMMENT * An implementation of the QuickSort algorithm. *;\n    COMMENT **                                             **;\n\n    INTEGER size, repeat;\n\n    COMMENT The recursive QUICKSORT procedure;\n    PROCEDURE quickSort(data) from: (first) to: (last);\n    VALUE first, last;  INTEGER first, last;  INTEGER ARRAY data;\n    BEGIN\n        INTEGER pivot, i, j, k;\n        SWITCH ss := loop;\n\n        IF first LESS last THEN BEGIN\n            pivot:=data[first];\n            j:=first;  k:=last;\n\n          loop:\n            FOR i:=0 WHILE data[j] LESS pivot AND j LESS last DO j:=j+1;\n            FOR i:=0 WHILE data[k] GREQ pivot AND k GR first DO k:=k-1;\n            IF j LESS k THEN BEGIN\n                i:=data[j];  data[j]:=data[k];  data[k]:=i;\n                GOTO loop;\n            END;\n\n            quickSort(data, first, k);\n            quickSort(data, k+1, last);\n        END;\n    END quickSort;\n\n    COMMENT Print data values;\n    PROCEDURE printData(s, data, size);\n    VALUE size;  STRING s;  INTEGER size;  INTEGER ARRAY data;\n    BEGIN\n        INTEGER i;\n        PRINT s;\n        FOR i:=1 STEP 1 UNTIL size DO\n            PRINT prefix({ }), digits(3), data[i];\n    END printData;\n\n    COMMENT Decrement a variable;\n    INTEGER PROCEDURE dec(i); INTEGER i; dec := i := i-1;\n\n    READ repeat, size;\n\n    BEGIN\n        INTEGER i, d;  INTEGER ARRAY data[1:size];\n        SWITCH ss := next;\n\n      next:\n        punch(3);\n\n        COMMENT Generate some random numbers from 0 to 511 (9 bits);\n        FOR i:=1 STEP 1 UNTIL size DO BEGIN\n            d:=511;\n            elliott(7,5, 8000, 0, 2,3, d);\n            data[i]:=d;\n        END;\n\n        printData({{L}Original Data:}, data, size);\n\n        quickSort(data, 1, size);\n\n        printData({{L}Sorted Data:  }, data, size);\n        PRINT {{L2}};\n\n        IF dec(repeat) GR 0 THEN GOTO next;\n    END;\nEND program;\n\nRepeat 3 times with 12 values\nRepeat 4 times with 10 values\n", "random.a1": "**                              **\n* Elliott Model 803B Simulator   *\n*                                *\n* (C) Copyright Tim Baldwin 2009 *\n**                              **\n\n**\n* Random number example\n*\n* Writes random values to random storage locations\n**\n                @entry\n\nstart:          start                   * Marks the start of this program\nabits:          8191                    * Address bits mask\ndbits:          3                       * Data value mask\ntemp:           0                       * Working storage\n\nentry:          75 8000 : 03 abits      * Get a random address\n                20 temp : 05 start      * Make sure we don\u0027t overwrite the code!\n                41 good : 40 entry\n\ngood:           75 8000 : 03 dbits      * Get a random value (0 to 3)\n                00 temp / 20 0          * Store in random location\n                40 entry                * And repeat forever\n\n\n", "charset.a1": "**                              **\n* Elliott Model 803B Simulator   *\n*                                *\n* (C) Copyright Tim Baldwin 2009 *\n**                              **\n\n**\n* Procedure call example\n*\n* Prints the character set to the teletype\n**\n\n        @entry                  * Entry point\n\nentry:  00   LS / 74  4096      * Print letter shift\n        73 link : 40 chars      * Procedure call to write characters\n        00   FS / 74  4096      * Print figure shift\n        73 link : 40 chars      * Procedure call\n        72 8191                 * Exit\n\nlink:   0                       * Stores return address\nchars:  26   ch : 32    ch      * Clear ch, increment ch\n        05  max : 42   rtn      * Check for end\n        00   ch / 74  4096      * Write character\n        74 4124 : 44 chars      * Write space and loop\nrtn:    74 4125 : 74  4126      * Write final CR LF\n        00 link / 40     1      * Return to address in link plus 1\n\nch:     0                       * Workspace\nmax:    26                      * Last character value\nLS:     31                      * Letter shift\nFS:     27                      * Figure shift\n", "plot.algol": "Waveform Plots;\n\nBEGIN\n    COMMENT **                         **;\n    COMMENT * Elliott 803B simulator    *;\n    COMMENT *                           *;\n    COMMENT * (C) Tim Baldwin 2010,2013 *;\n    COMMENT **                         **;\n    COMMENT **                        **;\n    COMMENT * Draw various waveform    *;\n    COMMENT * functions on the plotter *;\n    COMMENT **                        **;\n\n    INTEGER orgX, orgY, lastX, lastY; \n    REAL scaleX, scaleY;\n\n    COMMENT Set plot origin and the X and Y scaling factor;\n    PROCEDURE setOrigin(x, y, sx, sy);  VALUE x, y, sx, sy;  \n            INTEGER x, y;  REAL sx, sy;\n    BEGIN \n        INTEGER i;\n        scaleX := sx;  scaleY := sy;\n        orgX := x;  orgY := y;\n        lastX := lastY := 0;\n        \n        COMMENT reset the pen to the left hand edge;\n        FOR i := 1 STEP 2 UNTIL 1100 DO ELLIOTT(7,2,7170, 0, 7,2,7170);\n    END setOrigin;\n\n    COMMENT Plot an approximate straight line from the current position to\n        the new location.  This is actually a very poor straight line\n        as it just uses the legs of a right angle triangle.  It only really\n        works if lines are truly horizontal or vertical or are very short.\n        This just happens to be the case for all output from this program.;\n    PROCEDURE plotTo(x, y);  VALUE x, y;  REAL x, y;\n    BEGIN \n        INTEGER ix, iy, i, w, h;\n        INTEGER sw, sh, pw, ph;\n\n        COMMENT calculate the lengths of the triangle legs;\n        ix := x*scaleX + orgX;  iy := y*scaleY + orgY;\n        w := ix - lastX;  h := iy - lastY;\n\n        COMMENT set the plotter movement details;\n        sw := IF w LESS 0 THEN -w ELSE w;\n        pw := IF w LESS 0 THEN 7170 ELSE 7169;\n        sh := IF h LESS 0 THEN -h ELSE h;\n        ph := IF h LESS 0 THEN 7176 ELSE 7172;\n\n        COMMENT plot trying to be smart about which direction to move first;\n        IF (y GR 0 AND h GR 0) OR (y LESS 0 AND h LESS 0) THEN BEGIN\n            IF sh GR 0 THEN\n                FOR i := 1 STEP 1 UNTIL sh DO ELLIOTT(0,0,ph, 1, 7,2,0);\n            IF sw GR 0 THEN\n                FOR i := 1 STEP 1 UNTIL sw DO ELLIOTT(0,0,pw, 1, 7,2,0);\n        END ELSE BEGIN\n            IF sw GR 0 THEN\n                FOR i := 1 STEP 1 UNTIL sw DO ELLIOTT(0,0,pw, 1, 7,2,0);\n            IF sh GR 0 THEN\n                FOR i := 1 STEP 1 UNTIL sh DO ELLIOTT(0,0,ph, 1, 7,2,0);\n        END;\n\n        COMMENT save final position;\n        lastX := ix;  lastY := iy;\n    END plotTo;\n\n    COMMENT Move pen to new location;\n    PROCEDURE moveTo(x, y);  VALUE x, y;  REAL x, y;\n    BEGIN \n        ELLIOTT(7,2,7184, 0, 0,0,0);\n        plotTo(x, y);\n    END moveTo;\n\n    COMMENT Draw line to new location;\n    PROCEDURE drawTo(x, y);  VALUE x, y;  REAL x, y;\n    BEGIN \n        ELLIOTT(7,2,7200, 0, 0,0,0);\n        plotTo(x, y);\n    END drawTo;\n\n    COMMENT Main program;\n    BEGIN \n        REAL theta, pi;\n        \n        REAL PROCEDURE charge(x);  VALUE x;  REAL x;\n        BEGIN\n            BOOLEAN rise;\n            REAL y, z;\n            \n            rise := x LESS pi;\n            y := IF rise THEN x ELSE x-pi;\n            \n            z := 2*(1-exp(-y*2)) - 1;\n            \n            charge := IF rise THEN z ELSE 0-z;\n        END;  \n        \n        PROCEDURE plotFn(x, fn);  REAL x, fn;\n        BEGIN \n            INTEGER i;\n            BOOLEAN PROCEDURE divides(a, b);  VALUE a, b;  INTEGER a, b;\n                divides := (a DIV b)*b = a;\n            REAL PROCEDURE radians(d);  VALUE d;  INTEGER d;\n                radians := d/180 * pi;    \n        \n            COMMENT Draw the axes;\n            moveTo(0, -1);\n            drawTo(0, 1);\n            moveTo(0, 0);\n            drawTo(360, 0);\n            FOR i := 360 STEP -15 UNTIL 15 DO BEGIN\n                moveTo(i, 0);\n                drawTo(i, IF divides(i,90) THEN 0.1 ELSE\n                              IF divides(i,30) THEN 0.05 ELSE 0.025);\n            END;\n            \n            COMMENT Draw the function;\n            x := radians(0);\n            moveTo(0, fn);\n            FOR i := 1 STEP 1 UNTIL 360 DO BEGIN\n                x := radians(i); \n                drawTo(i, fn);\n            END;\n            moveTo(0, 0);\n        END;\n        \n        COMMENT Define constant PI for use in several places;\n        pi := arccos(-1);\n    \n        PRINT PUNCH(3), {Plotting Cosine Function{L}};\n        setOrigin(100, 0, 1, 200);\n        plotFn(theta, cos(theta));\n        \n        PRINT PUNCH(3), {Plotting Square Root of Sine Function{L}};\n        setOrigin(650, 0, 1, 200);\n        plotFn(theta, sign(sin(theta))*sqrt(abs(sin(theta))));\n        \n        PRINT PUNCH(3), {Plotting Ramp Function{L}};\n        setOrigin(100, -500, 1, 200);\n        plotFn(theta, IF theta LESS pi THEN 2*theta/pi-1 ELSE 2*theta/pi-3);\n        \n        PRINT PUNCH(3), {Plotting Exponential Charge/Discharge Function{L}};\n        setOrigin(650, 0, 1, 200);\n        plotFn(theta, charge(theta));\n    END;\nEND program;\n", "print.a1": "**                              **\n* Elliott Model 803B Simulator   *\n*                                *\n* (C) Copyright Tim Baldwin 2009 *\n**                              **\n\n**\n* Tape Printer\n*\n* Prints the contents of the tape in reader 2 to the teletype.\n*\n* This will skip leading blanks and will terminate when a trailing blank\n* is found.\n**\n\n       @entry               * Entry point\n\nentry: 06    0 : 20 char    * Set ACC and workspace to zero\nskip:  71 2048 : 42 skip    * Skip leading blanks\nloop:  20 char / 74 4096    * Write character to teletype\n       06    0 : 71 2048    * Read next character\n       42  end : 40 loop    * End when blank tape found\n\nend:   72 8191              * Exit\n\nchar:  0                    * Character workspace\n", "hello2.a1": "**                              **\n* Elliott Model 803B Simulator   *\n*                                *\n* (C) Copyright Tim Baldwin 2009 *\n**                              **\n\n**\n* Simple Hello World Example\n*\n* Prints \"HELLO WORLD?\" to the teletype.\n*\n* This program will be loaded into into store starting at address 7.  The\n* initial instructions will read past the end of the input tape and the\n* system will become \u0027busy\u0027 waiting for more input from the tape reader.\n* At this point the operator needs to press the \u0027Reset\u0027 button and perform\n* a manual jump to the entry point address (40 7).\n**\n        =7                      * Load address\n\nloop:   22 index / 30 hello     * Get next character\n        42 end   : 20 char      * Check for zero at end of text, otherwise save character\n        00 char  / 74 4096      * Write character to teletype\n        40 loop                 * Loop\nend:    74 4125  : 74 4126      * Write [CR][LF] to terminate line\ndone:   40 done                 * Finished, so spin until reset\n\nchar:   0                       * Character workspace\nindex: -1                       * Index into text\nhello: \u0027Hello World!\u0027           * Text: will be telecode [LS]HELLO WORLD[FS]?\n        0                       * Zero marks end of text\n", "factorial4.algol": "Factorial4\u0027\nBEGIN\n\nComment ****************************************************************\n        ***                                                          ***\n        *** Calculate factorial of a given number...                 ***\n        ***                                                          ***\n        *** Written: For 503 Algol - August 1968                     ***\n        *** Amended: For 803 Algol -    May 2010                     ***\n        *** Author:  Bob Firth                                       ***\n        *** Contact: General_Factotum@hotmail.co.uk                  ***\n        ***                                                          ***\n        *** Written: June,July 2010                                  ***\n        *** Ver 2.0: Calculations performed in binary                ***\n        *** Ver 3.0: Tidy-up +Trace-   June 2010                     ***\n        *** Ver 4.0: Final tidy code   July 2010                     ***\n        ***                                                          ***\n        *** Definition of factorial N = N*(N-1)*(N-2)......*3*2*1    ***\n        *** Basic \"tricks\" to speedup on original algorithm (1968)   ***\n        *** (1) Work in binary, not decimal, and then convert result ***\n        ***     to decimal for printing out at end.                  ***\n        *** (2) Only multiply that part of (partial) result array    ***\n        ***     which is currently non-zero.                         ***\n        *** (3) Assemble as many consecutive multipliers into one    ***\n        ***     word as possible, before applying to the main        ***\n        ***     multi-precision array.                               ***\n        ***                                                          ***\n        *** NB  The style of coding could do with being made more    ***\n        ***     modular (using procedures)                           ***\n        ***     This would then allow more intelligent way of        ***\n        ***     handling array bounds (depending on requested number)***\n        ***                                                          ***\n        *** Diagnostics  To view assembly of multipliers, set B-Line ***\n        *** ===========  on the console word generator...            ***\n        ***                                                          ***\n        *** Finally - you can check result(s) at WWW.WolframAlpha.com***\n        ***                                                          ***\n        ****************************************************************\u0027\n\n\nComment - Requested factorial, and variable used to count it\u0027\n        Integer Number,Count\u0027\n\nComment - Multiplication temporaries\u0027\n        Integer Factor,Carry\u0027\n\nComment - Division temporaries\u0027\n        Integer Remain,Temp\u0027\n\nComment - Array counters/pointers\u0027\n        Integer BMax,DMax,IPoint,OPoint,Point\u0027\n\nComment - Program constants - MaxPos=2**39-1, BLine=2**19\u0027\n        Integer MaxPos,Power,NDigit,One,BLine\u0027\n\nComment - Variables used for final printout\u0027\n        Integer Row,Rows,Cols\u0027\n\nComment - Misc Variables\u0027\n        Integer N,P,Trace\u0027\n\n        Real    pi,Estim\u0027\n        Integer Array BStore[1:800],DStore[1:1000]\u0027\n        Switch  SW1:=SAYSO2,START2,LOOP,OKAY,WORK,ONGO,NEXT,OFLO,SKIP,SKIP1\u0027\n        SWITCH  SW2:=SAYSO3,START3,LOOP1,NOTRAC,DECRE,INCRE,OKAY1,LOOP2\u0027\n        SWITCH  SW3:=LOOP3,OUT1,OUT2,OnYerBike\u0027\n\n        Reader(2)\u0027\n        Punch(3)\u0027\n        MaxPos  :=274877906943\u0027\n        BLine   :=524288\u0027\n        Power   :=10000000000\u0027\n        NDigit  :=entier(LN(Power)/LN(10)+0.5)\u0027\n        One     :=1\u0027\n\n        Read Number\u0027\n        Print l1? Calculating Factorial?,sameline,digits(4),Number\u0027\n\n\n        PRINT l2? Stage 1 - estimates of result?\u0027\n        PRINT l1? =============================?\u0027\n\n        Digits(5)\u0027\n        pi      :=3.14159265\u0027\n        Estim   :=(0.5*LN(2*pi)+(Number+0.5)*LN(Number)-Number)/LN(10)\u0027\n        Print l1?  Stirling ?,sameline,aligned(1,8),10**(Estim-entier(Estim))\n                , x 10 to power?,entier(Estim)\u0027\n\n        Estim   :=(Number*LN(Number)-Number+LN(Number*(1+4*Number*(1+2*Number)))/6+LN(pi)/2)/LN(10)\u0027\n        Print l1? Ramanujan ?,sameline,aligned(1,8),10**(Estim-entier(Estim))\n                , x 10 to power?,entier(Estim)\u0027\n\n\n        PRINT l2? Stage 2 - Calculate result in Binary?\u0027\n        PRINT l1? ====================================?\u0027\n\n        PRINT l1? Clear binary store...?\u0027\n        FOR N:=2 STEP 1 UNTIL 800 DO BStore[N]:=0\u0027\n                \n        BStore[1]:=1\u0027\n        BMax    :=1\u0027\n        Count   :=1\u0027\n        Elliott(7,0,0     ,0,0,3,BLine )\u0027\n        Elliott(4,2,SAYSO2,0,4,0,START2)\u0027\nSAYSO2: Print l1? Working...?\u0027\n\nComment - Here we stuff as many consecutive integer multiples into a 38 bit word\n          as possible - result in Factor\u0027\nSTART2: Factor  :=1\u0027\n        Elliott(7,0,0     ,0,0,3,BLine )\u0027\n        Elliott(2,0,Trace ,0,4,2,LOOP  )\u0027\n        PRINT l1? Multipliers?,sameline,digits(4),Count+1\u0027\nLOOP:   ELLIOTT(3,0,Number,0,0,5,Count )\u0027\n        ELLIOTT(4,2,WORK  ,0,0,2,Count )\u0027\n        ELLIOTT(5,2,Factor,0,4,2,OKAY  )\u0027\n        ELLIOTT(4,0,WORK  ,0,0,0,0     )\u0027\nOKAY:   ELLIOTT(5,7,0     ,0,2,0,Factor)\u0027\n        ELLIOTT(2,2,Count ,0,4,0,LOOP  )\u0027\nWORK:   Elliott(3,0,Trace ,0,4,2,ONGO  )\u0027\n        PRINT  to ?,sameline,digits(4),Count, Gives Factor?,digits(12),Factor\u0027\n\nComment - Now we take the product in Factor, and multiply into the multi precision\n          binary number held in BStore()\u0027\nONGO:   Point   :=ADDRESS(BStore)-1\u0027\n        Elliott(2,6,Carry ,0,2,6,N     )\u0027\nNEXT:   Elliott(2,2,Point ,0,3,0,Factor)\u0027\n        Elliott(0,0,Point ,1,5,2,0     )\u0027\n        Elliott(2,0,4     ,0,5,7,0     )\u0027\n        Elliott(0,4,Carry ,0,4,3,OFLO  )\u0027\n        Elliott(4,0,SKIP  ,0,0,0,0     )\u0027\nOFLO:   Elliott(0,3,MaxPos,0,2,2,4     )\u0027\nSKIP:   Elliott(0,0,Point ,1,2,0,0     )\u0027\n        Elliott(3,0,4     ,0,2,0,Carry )\u0027\n        Elliott(3,2,N     ,0,0,5,BMax  )\u0027\n        Elliott(4,1,NEXT  ,0,0,0,0     )\u0027\n        Elliott(0,0,Point ,1,3,0,0     )\u0027\n        Elliott(4,2,SKIP1 ,0,2,2,BMax  )\u0027\nSKIP1:  IF Count LESS Number THEN GOTO START2\u0027\n        PRINT L1?  Binary storage used is?,SAMELINE,digits(3),BMax, Words?\u0027\n\n\n        PRINT l2? Stage 3 - Convert to Decimal?\u0027\n        PRINT l1? ============================?\u0027\n\n        Elliott(7,0,0     ,0,0,3,BLine )\u0027\n        Elliott(4,2,SAYSO3,0,4,0,START3)\u0027\nSAYSO3: Print l1? Working...?\u0027\n\nSTART3: IPoint  :=ADDRESS(BStore)-1\u0027\n        OPoint  :=ADDRESS(DStore)-1\u0027\n        DMax    :=0\u0027\n\tN\t:=-1\u0027\nLOOP1:  Elliott(7,0,0     ,0,0,3,BLine )\u0027\n        Elliott(4,2,NOTRAC,0,2,2,N     )\u0027\n\tIF N = (N DIV 70)*70 THEN PRINT l1??\u0027\n\tPRINT SAMELINE,.?\u0027\nNOTRAC: Elliott(3,0,BMax  ,0,4,2,OUT2  )\u0027\n        Elliott(0,4,IPoint,0,2,0,Point )\u0027\n        Elliott(0,0,Point ,1,3,0,0     )\u0027\n        Elliott(4,2,DECRE ,0,0,5,Power )\u0027\n        Elliott(4,1,OKAY1 ,0,4,0,INCRE )\u0027\nDECRE:  Elliott(3,0,One   ,0,2,7,BMax  )\u0027\n        Elliott(4,0,NOTRAC,0,0,0,0     )\u0027\nINCRE:  Elliott(2,2,BMax  ,0,2,2,Point )\u0027\nOKAY1:  Elliott(0,6,Point ,1,1,0,0     )\u0027\n        Elliott(2,0,Remain,0,3,0,One   )\u0027\n        Elliott(2,7,Point ,0,4,0,LOOP3 )\u0027\nLOOP2:  Elliott(0,0,Point ,1,3,0,0     )\u0027\n        Elliott(2,0,4     ,0,5,0,38    )\u0027\n        Elliott(3,0,Remain,0,5,6,Power )\u0027\n        Elliott(0,0,Point ,1,2,0,0     )\u0027\n        Elliott(5,2,Power ,0,5,7,0     )\u0027\n        Elliott(0,7,4     ,0,0,3,Maxpos)\u0027\n        Elliott(2,0,Remain,0,0,0,0     )\u0027\n        Elliott(3,0,One   ,0,3,7,Point )\u0027\nLOOP3:  Elliott(3,0,Point ,0,0,5,IPoint)\u0027\n        Elliott(4,2,OUT1  ,0,4,0,LOOP2 )\u0027\n\nOUT1:   Elliott(2,2,DMax  ,0,3,0,DMax  )\u0027\n        Elliott(0,4,OPoint,0,2,0,4     )\u0027\n        Elliott(3,0,Remain,0,0,0,0     )\u0027\n        Elliott(0,0,4     ,1,2,0,0     )\u0027\n        Elliott(3,0,BMax  ,0,0,5,One   )\u0027\n        Elliott(4,2,OUT2  ,0,4,0,LOOP1 )\u0027\n\nOUT2:   PRINT l1? Decimal storage used is?,SAMELINE,digits(3),DMax, Words?\u0027\n        Print l2? Factorial?,sameline,digits(4),Number, is:?,l1??\u0027\n\n        Cols    :=7\u0027\n        Digits(NDigit)\u0027\n        Rows    :=( DMax+Cols-1 ) DIV Cols\u0027\n        FOR Row:=Rows STEP -1 UNTIL 1 DO BEGIN\n                Print l1??\u0027\n                FOR P:=Cols STEP -1 UNTIL 1 DO BEGIN                        \n                        N       :=(Row-1)*Cols+P\u0027\n                        If N GR   DMax THEN Print            ?\u0027\n                        If N =    DMax THEN Print sameline,DStore[N]\u0027\n                        If N LESS DMax THEN Print sameline,leadzero(0?),DStore[N]\u0027\n                                               End\u0027\n                                         End\u0027\n\n        Print l1? Numer of digits?,sameline,digits(4)\n                ,(DMax-1)*NDigit+entier(1+LN(DStore[DMax])/LN(10))\u0027\nEnd\u0027\nComment ======================================\\\\======================================\u0027\n" } };